73	func (s *Service) GetAvailableHandsets(ctx context.Context, serviceID string) ([]models.Handset, error) {
74		if serviceID == "" {
75			return nil, fmt.Errorf("service_id is required: %w", terrors.ErrBadRequest)
76		}
77	
78		// If the customer already has an active contract on this service, return empty list
79		_, err := s.store.GetActiveContractForService(ctx, serviceID)
80		if err == nil {
81			tlog.WithAttribute("service_id", serviceID).
82				Info(ctx, "active contract exists, returning empty handset list")
83			return nil, nil
84		}
85		if !errors.Is(err, terrors.ErrNotFound) {
86			return nil, fmt.Errorf("failed to check active contract: %w", err)
87		}
88	
89		handsets, err := s.store.GetHandsets(ctx, true)
90		if err != nil {
91			return nil, fmt.Errorf("failed to get handsets: %w", err)
92		}
93	
94		tlog.WithAttribute("service_id", serviceID).
95			WithAttribute("count", fmt.Sprintf("%d", len(handsets))).
96			Info(ctx, "returning available handsets")
97	
98		return handsets, nil
99	}
