147	func (s *Service) GetActiveContractForService(ctx context.Context, serviceID string) (*models.Contract, error) {
148		if serviceID == "" {
149			return nil, fmt.Errorf("service_id is required: %w", terrors.ErrBadRequest)
150		}
151	
152		contract, err := s.store.GetActiveContractForService(ctx, serviceID)
153		if err != nil {
154			if errors.Is(err, terrors.ErrNotFound) {
155				return nil, fmt.Errorf("no active contract found for service: %w", terrors.ErrNotFound)
156			}
157			return nil, fmt.Errorf("failed to get active contract: %w", err)
158		}
159	
160		return contract, nil
161	}
