277	// EligibilityCallbackSuccess handles the callback from the eligibility provider once the
278	// eligibility check has completed. The outcome.Decision field determines the result.
279	func (s *Service) EligibilityCallbackSuccess(ctx context.Context, requestID string, outcome models.EligibilityOutcome) error {
280		if requestID == "" {
281			return fmt.Errorf("request_id is required: %w", terrors.ErrBadRequest)
282		}
283	
284		contract, err := s.store.GetContractByRequestID(ctx, requestID)
285		if err != nil {
286			return fmt.Errorf("failed to get contract: %w", err)
287		}
288	
289		// Only the first eligibility callback should move a contract out of pending.
290		if contract.Status != models.ContractStatusPendingEligibility {
291			tlog.WithAttribute("request_id", requestID).
292				WithAttribute("current_status", string(contract.Status)).
293				Info(ctx, "eligibility callback ignored, contract is not pending eligibility")
294			return nil
295		}
296	
297		if err := s.store.UpdateContractEligibilityApproved(ctx, requestID, outcome); err != nil {
298			return fmt.Errorf("failed to update contract status: %w", err)
299		}
300	
301		if err := s.eventProducer.ProduceMobileHandsetContractApprovedSync(ctx, &serviceevents.MobileHandsetContractApproved{
302			ServiceId:      contract.ServiceID,
303			CustomerId:     contract.CustomerID,
304			ContractId:     contract.ID.String(),
305			HandsetId:      contract.HandsetID,
306			HandsetName:    contract.HandsetName,
307			ContractPrice:  money(contract.ContractPrice),
308			RetailPrice:    money(contract.RetailPrice),
309			ContractMonths: contract.ContractMonths,
310		}); err != nil {
311			tlog.WithError(err).
312				WithAttribute("contract_id", contract.ID.String()).
313				Error(ctx, "failed to produce MobileHandsetContractApproved event")
314		}
315	
316		tlog.WithAttribute("request_id", requestID).
317			WithAttribute("contract_id", contract.ID.String()).
318			WithAttribute("decision", outcome.Decision).
319			Info(ctx, "eligibility approved, contract awaiting loan processing")
320	
321		return nil
322	}
323	
324	// EligibilityCallbackFailure handles a failure callback from the eligibility provider,
325	// indicating the eligibility process could not be completed (e.g. KYC or credit check failure).
326	func (s *Service) EligibilityCallbackFailure(ctx context.Context, requestID string, outcome models.EligibilityFailureOutcome) error {
327		if requestID == "" {
328			return fmt.Errorf("request_id is required: %w", terrors.ErrBadRequest)
329		}
330	
331		contract, err := s.store.GetContractByRequestID(ctx, requestID)
332		if err != nil {
333			return fmt.Errorf("failed to get contract: %w", err)
334		}
335	
336		if contract.Status != models.ContractStatusPendingEligibility {
337			tlog.WithAttribute("request_id", requestID).
338				WithAttribute("current_status", string(contract.Status)).
339				Info(ctx, "eligibility failure callback ignored, contract is not pending eligibility")
340			return nil
341		}
342	
343		if err := s.store.UpdateContractEligibilityFailed(ctx, requestID, outcome); err != nil {
344			return fmt.Errorf("failed to update contract status: %w", err)
345		}
346	
347		if err := s.eventProducer.ProduceMobileHandsetContractDeclinedSync(ctx, &serviceevents.MobileHandsetContractDeclined{
348			ServiceId:  contract.ServiceID,
349			CustomerId: contract.CustomerID,
350			ContractId: contract.ID.String(),
351			HandsetId:  contract.HandsetID,
352		}); err != nil {
353			tlog.WithError(err).
354				WithAttribute("contract_id", contract.ID.String()).
355				Error(ctx, "failed to produce MobileHandsetContractDeclined event")
356		}
357	
358		tlog.WithAttribute("request_id", requestID).
359			WithAttribute("contract_id", contract.ID.String()).
360			Info(ctx, "eligibility failed, contract declined")
361	
362		return nil
363	}
364	
365	// EligibilityStatusUpdate handles status update notifications from the eligibility provider.
366	// For DECLINED and WITHDRAWN statuses, the contract is moved to DECLINED.
367	func (s *Service) EligibilityStatusUpdate(ctx context.Context, requestID, statusStr string) error {
368		// @todo matt - this is a bit of a catch-all for any future status updates from the eligibility provider that require action. we don't really know what the statuses in the proto actually represent at this stage, neither do we know which are terminal states and how they should interact with the success/failure callbacks. consider this method WIP for the time being.
369		if requestID == "" {
370			return fmt.Errorf("request_id is required: %w", terrors.ErrBadRequest)
371		}
372	
373		if statusStr != "DECLINED" && statusStr != "WITHDRAWN" {
374			tlog.WithAttribute("request_id", requestID).
375				WithAttribute("status", statusStr).
376				Info(ctx, "eligibility status update received, no action required")
377			return nil
378		}
379	
380		contract, err := s.store.GetContractByRequestID(ctx, requestID)
381		if err != nil {
382			return fmt.Errorf("failed to get contract: %w", err)
383		}
384	
385		if contract.Status != models.ContractStatusPendingEligibility {
386			tlog.WithAttribute("request_id", requestID).
387				WithAttribute("current_status", string(contract.Status)).
388				Info(ctx, "eligibility status update ignored, contract is not pending eligibility")
389			return nil
390		}
391	
392		if err := s.store.UpdateContractStatus(ctx, requestID, models.ContractStatusDeclined); err != nil {
393			return fmt.Errorf("failed to update contract status: %w", err)
394		}
395	
396		if err := s.eventProducer.ProduceMobileHandsetContractDeclinedSync(ctx, &serviceevents.MobileHandsetContractDeclined{
397			ServiceId:  contract.ServiceID,
398			CustomerId: contract.CustomerID,
399			ContractId: contract.ID.String(),
400			HandsetId:  contract.HandsetID,
401		}); err != nil {
402			tlog.WithError(err).
403				WithAttribute("contract_id", contract.ID.String()).
404				Error(ctx, "failed to produce MobileHandsetContractDeclined event")
405		}
406	
407		tlog.WithAttribute("request_id", requestID).
408			WithAttribute("contract_id", contract.ID.String()).
409			WithAttribute("status", statusStr).
410			Info(ctx, "eligibility status update, contract declined")
411	
412		return nil
413	}
414	
415	// money converts a pence integer string (e.g. "4200") to a Money message with
416	// the amount expressed in pounds (e.g. "42.00"). The Money type is consumed by
417	// downstream services that treat Amount as a decimal pound value.
418	func money(penceStr string) *serviceevents.Money {
419		pence, err := strconv.Atoi(penceStr)
420		if err != nil {
421			return &serviceevents.Money{Amount: penceStr, Currency: currencyGBP}
422		}
423		return &serviceevents.Money{
424			Amount:   fmt.Sprintf("%.2f", float64(pence)/100),
425			Currency: currencyGBP,
426		}
427	}
428	
429	func eligibilityRedirectURL(providerURL, requestID string) (string, error) {
430		u, err := url.Parse(providerURL)
431		if err != nil {
432			return "", fmt.Errorf("failed to parse eligibility provider URL: %w", err)
433		}
434	
435		query := u.Query()
436		query.Set("request_id", requestID)
437		u.RawQuery = query.Encode()
438	
439		return u.String(), nil
440	}
