56	func (c *Consumer) ConsumeMobileHandsetContractApproved(ctx context.Context, env *message.Envelope,
57		in *serviceevents.MobileHandsetContractApproved, ack func() error,
58	) error {
59		contractIDStr := in.GetContractId()
60		serviceID := in.GetServiceId()
61		customerID := in.GetCustomerId()
62		handsetID := in.GetHandsetId()
63	
64		contractID, err := uuid.Parse(contractIDStr)
65		if err != nil {
66			return fmt.Errorf("invalid contract_id %q: %w", contractIDStr, err)
67		}
68	
69		tlog.WithAttribute("contract_id", contractIDStr).
70			WithAttribute("service_id", serviceID).
71			WithAttribute("handset_id", handsetID).
72			Info(ctx, "processing handset contract approved event")
73	
74		// Look up contract — we need the request_id and bank details
75		contract, err := c.store.GetContractByID(ctx, contractID)
76		if err != nil {
77			return fmt.Errorf("failed to load contract %s: %w", contractIDStr, err)
78		}
79	
80		// Idempotency: if already approved or ordered, skip.
81		if contract.Status == models.ContractStatusApproved || contract.Status == models.ContractStatusHandsetOrdered {
82			tlog.WithAttribute("contract_id", contractIDStr).
83				WithAttribute("status", string(contract.Status)).
84				Info(ctx, "contract already processed, skipping")
85	
86			return ack()
87		}
88	
89		// Fetch customer details from account-gateway
90		accountResp, err := c.accountClient.GetAccount(ctx, &accountgateway.GetAccountRequest{
91			AccountId: customerID,
92		})
93		if err != nil {
94			return fmt.Errorf("failed to fetch account for customer %s: %w", customerID, err)
95		}
96	
97		// Build loan request
98		retailPriceAmount := in.GetRetailPrice().GetAmount()
99		if retailPriceAmount == "" {
100			return fmt.Errorf("retail price is required for approved handset contract %s", contractIDStr)
101		}
102		retailPrice, err := strconv.ParseFloat(retailPriceAmount, 32)
103		if err != nil {
104			return fmt.Errorf("failed to parse approved event retail price %q: %w", retailPriceAmount, err)
105		}
106	
107		contractMonths := in.GetContractMonths()
108		if contractMonths == "" {
109			return fmt.Errorf("contract months is required for approved handset contract %s", contractIDStr)
110		}
111		contractTerm, err := strconv.ParseInt(contractMonths, 10, 32)
112		if err != nil {
113			return fmt.Errorf("failed to parse approved event contract months %q: %w", contractMonths, err)
114		}
115		if contractTerm < 1 || contractTerm > math.MaxInt32 {
116			return fmt.Errorf("approved event contract months %q is outside supported range", contractMonths)
117		}
118	
119		loanReq := loanboxclient.CreateLoanRequest{
120			RequestID:         contract.RequestID,
121			AmountApproved:    float32(retailPrice),
122			TermMonths:        int32(contractTerm),
123			InterestRate:      loanboxclient.DefaultInterestRate,
124			LoanProduct:       loanboxclient.DefaultLoanProduct(),
125			BankAccountNumber: contract.BankAccountNumber,
126			BankTitle:         contract.BankTitle,
127		}
128	
129		// Enrich with customer details
130		if accountResp.GetAccount() != nil {
131			acct := accountResp.GetAccount()
132			if contact := acct.GetContactDetails(); contact != nil {
133				loanReq.Email = contact.GetEmail()
134				loanReq.Phone = contact.GetMobile()
135				parts := strings.Fields(contact.GetSalutation())
136				if len(parts) >= 2 {
137					loanReq.FirstName = parts[0]
138					loanReq.LastName = strings.Join(parts[1:], " ")
139				}
140			}
141			if customer := acct.GetCustomerDetails(); customer != nil && customer.GetDateOfBirth() != nil {
142				dob := customer.GetDateOfBirth().AsTime()
143				loanReq.DateOfBirth = &dob
144			}
145			if address := acct.GetCorrespondenceAddress(); address != nil {
146				loanReq.StreetAddress = strings.Join(address.GetFormattedLines(), ", ")
147				loanReq.CountryCode = "GB"
148			}
149		}
150	
151		tlog.WithAttribute("contract_id", contractIDStr).
152			WithAttribute("request_id", contract.RequestID).
153			WithAttribute("amount", fmt.Sprintf("%.2f", retailPrice)).
154			WithAttribute("term_months", strconv.FormatInt(contractTerm, 10)).
155			Info(ctx, "submitting loan request to Loanbox")
156	
157		loanResp, err := c.loanboxClient.CreateLoan(ctx, loanReq)
158		if err != nil {
159			return fmt.Errorf("loanbox loan creation failed for contract %s: %w", contractIDStr, err)
160		}
161	
162		// Store loan reference
163		loanRef := strconv.FormatInt(loanResp.LoanApplicationID, 10)
164		if err := c.store.UpdateContractLoanReference(ctx, contract.RequestID, loanRef); err != nil {
165			return fmt.Errorf("failed to store loan reference for contract %s: %w", contractIDStr, err)
166		}
167	
168		if err := c.store.UpdateContractStatus(ctx, contract.RequestID, models.ContractStatusApproved); err != nil {
169			if errors.Is(err, terrors.ErrConflict) {
170				tlog.WithAttribute("contract_id", contractIDStr).
171					Info(ctx, "contract status changed before approval update, skipping")
172	
173				return ack()
174			}
175	
176			return fmt.Errorf("failed to update contract %s to APPROVED: %w", contractIDStr, err)
177		}
178	
179		tlog.WithAttribute("contract_id", contractIDStr).
180			WithAttribute("loan_ref", loanRef).
181			Info(ctx, "loan created, contract approved")
182	
183		return ack()
184	}
