186	func (c *Consumer) ConsumeMobileHandsetOrdered(ctx context.Context, env *message.Envelope,
187		in *serviceevents.MobileHandsetOrdered, ack func() error,
188	) error {
189		contractIDStr := in.GetContractId()
190		if contractIDStr == "" {
191			return fmt.Errorf("contract_id is required for MobileHandsetOrdered %s", env.GetId())
192		}
193	
194		contractID, err := uuid.Parse(contractIDStr)
195		if err != nil {
196			return fmt.Errorf("invalid contract_id %q: %w", contractIDStr, err)
197		}
198	
199		contract, err := c.store.GetContractByID(ctx, contractID)
200		if err != nil {
201			return fmt.Errorf("failed to load contract %s: %w", contractIDStr, err)
202		}
203		if contract.Status == models.ContractStatusHandsetOrdered {
204			tlog.WithAttribute("contract_id", contractIDStr).
205				Info(ctx, "contract already HANDSET_ORDERED, skipping")
206	
207			return ack()
208		}
209		if contract.Status != models.ContractStatusApproved {
210			return fmt.Errorf("contract %s is not ready to mark HANDSET_ORDERED: status %s", contractIDStr, contract.Status)
211		}
212	
213		if err := c.store.UpdateContractStatusByID(ctx, contractID, models.ContractStatusHandsetOrdered); err != nil {
214			if errors.Is(err, terrors.ErrConflict) {
215				tlog.WithAttribute("contract_id", contractIDStr).
216					WithAttribute("status", string(contract.Status)).
217					Info(ctx, "contract is not approved, skipping handset ordered update")
218				return ack()
219			}
220	
221			return fmt.Errorf("failed to update contract %s as ordered: %w", contractIDStr, err)
222		}
223	
224		tlog.WithAttribute("contract_id", contractIDStr).
225			Info(ctx, "contract marked handset ordered")
226	
227		return ack()
228	}
